import { Button } from "@/components/ui/button";
import { Parameter, ParameterValue, Tool, Command } from "@/registry/commandly/lib/types/commandly";
import { getCommandPath } from "@/registry/commandly/lib/utils/commandly";
import { TerminalIcon, CopyIcon, SaveIcon } from "lucide-react";
import { useCallback, useEffect, useState, useMemo } from "react";
import { toast } from "sonner";

interface GeneratedCommandProps {
  tool: Tool;
  selectedCommand?: Command;
  parameterValues: Record<string, ParameterValue>;
  onSaveCommand?: (command: string) => void;
}

export function GeneratedCommand({
  tool,
  selectedCommand,
  parameterValues,
  onSaveCommand,
}: GeneratedCommandProps) {
  selectedCommand = selectedCommand || tool.commands[0];
  const [generatedCommand, setGeneratedCommand] = useState("");

  const globalParameters = useMemo(() => {
    return tool.parameters?.filter((p) => p.isGlobal) || [];
  }, [tool]);

  const currentParameters = useMemo(() => {
    return tool?.parameters?.filter((p) => p.commandKey === selectedCommand.key) || [];
  }, [tool, selectedCommand]);

  const generateCommand = useCallback(() => {
    const commandPath = getCommandPath(selectedCommand, tool);
    let command = tool.name == commandPath ? tool.name : `${tool.name} ${commandPath}`;

    const parametersWithValues: Array<{
      param: Parameter;
      value: ParameterValue;
    }> = [];

    globalParameters.forEach((param) => {
      const value = parameterValues[param.key];
      if (value !== undefined && value !== "" && value !== false) {
        parametersWithValues.push({ param, value });
      }
    });

    currentParameters.forEach((param) => {
      const value = parameterValues[param.key];
      if (value !== undefined && value !== "" && value !== false && !param.isGlobal) {
        parametersWithValues.push({ param, value });
      }
    });

    const positionalParams = parametersWithValues
      .filter(({ param }) => param.parameterType === "Argument")
      .sort((a, b) => (a.param.position || 0) - (b.param.position || 0));

    parametersWithValues.forEach(({ param, value }) => {
      if (param.parameterType === "Flag") {
        if (value === true) {
          const flag = param.shortFlag || param.longFlag;
          if (flag) command += ` ${flag}`;
        }
      } else if (param.parameterType === "Option") {
        const flag = param.shortFlag || param.longFlag;
        if (flag) {
          const separator = param.keyValueSeparator ?? " ";
          command += ` ${flag}${separator}${value}`;
        }
      } else if (param.parameterType === "Argument") {
        command += ` ${value}`;
      }
    });

    positionalParams.forEach(({ value }) => {
      command += ` ${value}`;
    });

    setGeneratedCommand(command);
  }, [tool, parameterValues, selectedCommand, globalParameters, currentParameters]);

  useEffect(() => {
    generateCommand();
  }, [generateCommand]);

  const copyCommand = () => {
    navigator.clipboard.writeText(generatedCommand);
    toast("Command copied!");
  };

  return (
    <div>
      {tool.commands.length === 0 ? (
        <div className="py-8 text-center">
          <TerminalIcon className="mx-auto mb-4 h-12 w-12 text-muted-foreground" />
          <p className="text-muted-foreground">No commands available for this tool.</p>
        </div>
      ) : generatedCommand ? (
        <div className="space-y-4">
          <div className="rounded bg-muted p-4 font-mono text-sm">{generatedCommand}</div>
          <div className="flex gap-2">
            <Button
              onClick={copyCommand}
              variant="outline"
              className="flex-1"
            >
              <CopyIcon className="mr-2 h-4 w-4" />
              Copy Command
            </Button>
            {onSaveCommand && (
              <Button
                onClick={() => onSaveCommand(generatedCommand)}
                variant="outline"
                className="flex-1"
              >
                <SaveIcon className="mr-2 h-4 w-4" />
                Save Command
              </Button>
            )}
          </div>
        </div>
      ) : (
        <div className="py-8 text-center">
          <TerminalIcon className="mx-auto mb-4 h-12 w-12 text-muted-foreground" />
          <p className="text-muted-foreground">Configure parameters to generate the command.</p>
        </div>
      )}
    </div>
  );
}

export interface Command {
  key: string;
  parentCommandKey?: string;
  name: string;
  description?: string;
  isDefault?: boolean;
  sortOrder?: number;
}

export interface ParameterEnumValue {
  key: string;
  parameterKey: string;
  value: string;
  displayName: string;
  description?: string;
  isDefault?: boolean;
  sortOrder?: number;
}

export type ParameterValidationType =
  | "min_length"
  | "max_length"
  | "min_value"
  | "max_value"
  | "regex";

export interface ParameterValidation {
  key: string;
  parameterKey: string;
  validationType: ParameterValidationType;
  validationValue: string;
  errorMessage: string;
}

export type ParameterDependencyType = "requires" | "conflicts_with";

export interface ParameterDependency {
  key: string;
  parameterKey: string;
  dependsOnParameterKey: string;
  dependencyType: ParameterDependencyType;
  conditionValue?: string;
}

export type ParameterValue = string | number | boolean;

// eslint-disable-next-line @typescript-eslint/no-empty-object-type
export interface ToolMetadata {}

// eslint-disable-next-line @typescript-eslint/no-empty-object-type
export interface ParameterMetadata {
  tags?: string[];
}

export type ParameterType = "Flag" | "Option" | "Argument";

export type ParameterDataType = "String" | "Number" | "Boolean" | "Enum";

export interface Parameter {
  key: string;
  name: string;
  commandKey?: string;
  description?: string;
  metadata?: ParameterMetadata;
  parameterType: ParameterType;
  dataType: ParameterDataType;
  isRequired: boolean;
  isRepeatable: boolean;
  isGlobal: boolean;
  defaultValue?: string;
  shortFlag?: string;
  longFlag?: string;
  position?: number;
  sortOrder?: number;
  arraySeparator?: string;
  keyValueSeparator?: string;
  enumValues?: ParameterEnumValue[];
  validations?: ParameterValidation[];
  dependencies?: ParameterDependency[];
}

export type ExclusionType = "mutual_exclusive" | "required_one_of";

export interface ExclusionGroup {
  key?: string;
  commandKey?: string;
  name: string;
  exclusionType: ExclusionType;
  parameterKeys: string[];
}

export interface SavedCommand {
  key: string;
  command: string;
}

export interface Tool {
  name: string;
  displayName: string;
  description?: string;
  version?: string;
  category?: string;
  tags?: string[];
  url?: string;
  commands: Command[];
  parameters: Parameter[];
  exclusionGroups?: ExclusionGroup[];
  metadata?: ToolMetadata;
}

import type {
  ExclusionType,
  ParameterDataType,
  ParameterDependencyType,
  ParameterMetadata,
  ParameterType,
  ParameterValidationType,
  ToolMetadata,
} from "./commandly";

export interface NestedParameterEnumValue {
  value: string;
  displayName: string;
  description?: string;
  isDefault?: boolean;
  sortOrder?: number;
}

export interface NestedParameterValidation {
  validationType: ParameterValidationType;
  validationValue: string;
  errorMessage: string;
}

export interface NestedParameterDependency {
  dependsOnParameter: string;
  dependencyType: ParameterDependencyType;
  conditionValue?: string;
}

export interface NestedParameter {
  name: string;
  description?: string;
  parameterType: ParameterType;
  dataType: ParameterDataType;
  metadata?: ParameterMetadata;
  isRequired: boolean;
  isRepeatable: boolean;
  isGlobal: boolean;
  defaultValue?: string;
  shortFlag?: string;
  longFlag?: string;
  position?: number;
  sortOrder?: number;
  arraySeparator?: string;
  keyValueSeparator?: string;
  enumValues?: NestedParameterEnumValue[];
  validations?: NestedParameterValidation[];
  dependencies?: NestedParameterDependency[];
}

export interface NestedCommand {
  name: string;
  description?: string;
  isDefault: boolean;
  sortOrder: number;
  parameters: NestedParameter[];
  subcommands: NestedCommand[];
}

export interface NestedExclusionGroup {
  name: string;
  exclusionType: ExclusionType;
  parameters: string[];
}

export interface NestedTool {
  name: string;
  displayName: string;
  description?: string;
  version?: string;
  url?: string;
  globalParameters: NestedParameter[];
  commands: NestedCommand[];
  exclusionGroups?: NestedExclusionGroup[] | null;
  metadata?: ToolMetadata;
}

import type {
  Command,
  ExclusionGroup,
  Parameter,
  SavedCommand,
  Tool,
} from "@/registry/commandly/lib/types/commandly";

export const buildCommandHierarchy = (commands: Command[]): Command[] => {
  return commands.sort(
    (a, b) => (a.sortOrder ?? commands.indexOf(a)) - (b.sortOrder ?? commands.indexOf(b)),
  );
};

export const slugify = (text: string): string => {
  return text
    .toString()
    .toLowerCase()
    .trim()
    .replace(/\s+/g, "-") // Replace spaces with -
    .replace(/[^\w-]+/g, "") // Remove all non-word chars
    .replace(/--+/g, "-") // Replace multiple - with single -
    .replace(/^-+/, "") // Trim - from start of text
    .replace(/-+$/, ""); // Trim - from end of text
};

export const getCommandPath = (command: Command, tool: Tool): string => {
  const findCommandPath = (
    targetKey: string,
    commands: Command[],
    path: string[] = [],
  ): string[] | null => {
    for (const cmd of commands) {
      if (cmd.name === targetKey) {
        return [...path, cmd.name];
      }

      const childCommands = commands.filter((c) => c.parentCommandKey === cmd.key);
      if (childCommands.length > 0) {
        const subPath = findCommandPath(targetKey, childCommands, [...path, cmd.name]);
        if (subPath) {
          return subPath;
        }
      }
    }
    return null;
  };

  const rootCommands = tool.commands.filter((c) => !c.parentCommandKey);
  const path = findCommandPath(command.name, rootCommands);

  if (!path) return command.name;

  if (command.name === tool.name && command.isDefault) {
    return tool.name;
  }

  const rootCommand = tool.commands.find((c) => c.name === tool.name);
  if (rootCommand?.isDefault && path[0] === tool.name) {
    path[0] = tool.name;
  }

  return path.join(" ");
};

export const getAllSubcommands = (commandKey: string, commands: Command[]): Command[] => {
  const result: Command[] = [];

  const findSubcommands = (parentKey: string) => {
    commands.forEach((cmd) => {
      if (cmd.parentCommandKey === parentKey) {
        result.push(cmd);
        findSubcommands(cmd.key);
      }
    });
  };

  findSubcommands(commandKey);
  return result;
};

export const exportToStructuredJSON = (tool: Tool) => {
  const flattenCommand = (cmd: Command) => {
    return { ...cmd };
  };

  return {
    name: tool.name,
    displayName: tool.displayName,
    description: tool.description,
    version: tool.version,
    commands: tool.commands.map(flattenCommand),
    parameters: tool.parameters,
    exclusionGroups: tool.exclusionGroups,
    metadata: tool.metadata,
  };
};

export const flattenImportedData = (importedData: Record<string, unknown>): Tool => {
  const {
    name,
    displayName,
    commands = [],
    exclusionGroups = [],
    metadata = {
      supportedInput: [],
      supportedOutput: [],
    },
  } = importedData as {
    name: string;
    displayName?: string;
    parameters?: Parameter[];
    commands?: Record<string, unknown>[];
    exclusionGroups?: ExclusionGroup[];
    metadata?: Tool["metadata"];
  };

  const allParameters: Parameter[] = [];

  const flattenCommandParameters = (
    command: Record<string, unknown>,
    parentKey?: string,
  ): Command[] => {
    const {
      parameters = [],
      subcommands = [],
      ...commandData
    } = command as {
      parameters?: Parameter[];
      subcommands?: Record<string, unknown>[];
      [key: string]: unknown;
    };

    (parameters as Parameter[]).forEach((param: Parameter) => {
      allParameters.push({
        ...param,
        commandKey: command.key as string,
        isGlobal: !command.name,
      });
    });

    const flatCommand: Command = {
      ...commandData,
      parentCommandKey: parentKey,
    } as Command;

    const flatCommands = [flatCommand];

    (subcommands as Record<string, unknown>[]).forEach((subcmd) => {
      flatCommands.push(...flattenCommandParameters(subcmd, command.key as string));
    });

    return flatCommands;
  };

  const flatCommands: Command[] = [];
  (commands as Record<string, unknown>[]).forEach((cmd) => {
    flatCommands.push(...flattenCommandParameters(cmd));
  });

  return {
    name: name,
    displayName: displayName || name,
    commands: flatCommands,
    parameters: allParameters,
    exclusionGroups,
    metadata,
  };
};

export const defaultTool = (toolName?: string, displayName?: string): Tool => {
  const finalToolName = toolName || "my-tool";
  return {
    name: finalToolName,
    displayName: displayName || "My Tool",
    commands: [
      {
        key: slugify(finalToolName),
        name: finalToolName,
        description: "Main command",
        isDefault: true,
        sortOrder: 0,
      },
    ],
    parameters: [
      {
        key: "--help",
        name: "Help",
        description: "Displays help menu of tool",
        parameterType: "Flag",
        dataType: "String",
        isRequired: false,
        isGlobal: true,
        shortFlag: "-h",
        longFlag: "--help",
        isRepeatable: false,
      },
    ],
  };
};

export const validateDefaultValue = (
  parameter: Parameter,
): { isValid: boolean; error?: string } => {
  const { defaultValue, validations, dataType } = parameter;

  if (!defaultValue || !validations) return { isValid: true };

  switch (dataType) {
    case "Number":
      if (!/^-?\d+$/.test(defaultValue)) {
        return { isValid: false, error: "Default value must be an integer" };
      }
      break;
    case "Boolean":
      if (!["true", "false", "1", "0"].includes(defaultValue.toLowerCase())) {
        return {
          isValid: false,
          error: "Default value must be true/false or 1/0",
        };
      }
      break;
  }

  for (const validation of validations) {
    const value = dataType === "Number" ? Number(defaultValue) : defaultValue;

    switch (validation.validationType) {
      case "min_length":
        if (typeof value === "string" && value.length < Number(validation.validationValue)) {
          return {
            isValid: false,
            error: validation.errorMessage || "Value too short",
          };
        }
        break;
      case "max_length":
        if (typeof value === "string" && value.length > Number(validation.validationValue)) {
          return {
            isValid: false,
            error: validation.errorMessage || "Value too long",
          };
        }
        break;
      case "min_value":
        if (typeof value === "number" && value < Number(validation.validationValue)) {
          return {
            isValid: false,
            error: validation.errorMessage || "Value too small",
          };
        }
        break;
      case "max_value":
        if (typeof value === "number" && value > Number(validation.validationValue)) {
          return {
            isValid: false,
            error: validation.errorMessage || "Value too large",
          };
        }
        break;
      case "regex":
        if (typeof value === "string" && !new RegExp(validation.validationValue).test(value)) {
          return {
            isValid: false,
            error: validation.errorMessage || "Value doesn't match pattern",
          };
        }
        break;
    }
  }

  return { isValid: true };
};

export const createNewCommand = (parentKey?: string): Command => {
  const name = randomCommandName();
  return {
    key: slugify(name),
    parentCommandKey: parentKey,
    name,
    isDefault: false,
    sortOrder: 1,
  };
};

export const createNewParameter = (isGlobal: boolean, commandKey?: string): Parameter => {
  return {
    key: "",
    name: "",
    commandKey: isGlobal ? undefined : commandKey,
    parameterType: "Option",
    dataType: "String",
    isRequired: false,
    isRepeatable: false,
    isGlobal,
    longFlag: "",
  };
};

export const getSavedCommandsFromStorage = (toolId: string): SavedCommand[] => {
  try {
    const saved = localStorage.getItem(`saved-${toolId}`);
    return saved ? JSON.parse(saved) : [];
  } catch {
    return [];
  }
};

export const saveSavedCommandsToStorage = (toolId: string, commands: SavedCommand[]): void => {
  try {
    localStorage.setItem(toolId, JSON.stringify(commands));
  } catch (error) {
    console.error("Failed to save commands to localStorage:", error);
  }
};

export const addSavedCommandToStorage = (toolId: string, command: SavedCommand): void => {
  const existingCommands = getSavedCommandsFromStorage(toolId);
  const updatedCommands = [...existingCommands, command];
  saveSavedCommandsToStorage(toolId, updatedCommands);
};

export const removeSavedCommandFromStorage = (toolId: string, commandKey: string): void => {
  const existingCommands = getSavedCommandsFromStorage(toolId);
  const updatedCommands = existingCommands.filter((cmd) => cmd.key !== commandKey);
  saveSavedCommandsToStorage(toolId, updatedCommands);
};

export const clearSavedCommandsFromStorage = (toolId: string): void => {
  localStorage.removeItem(toolId);
};

export const randomCommandName = () => {
  const characters = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz";
  let result = "";
  const charactersLength = characters.length;
  for (let i = 0; i < 7; i++) {
    result += characters.charAt(Math.floor(Math.random() * charactersLength));
  }
  return result;
};

export function generateHashCode(s: string): string {
  let h = 0;
  for (let i = 0; i < s.length; i++) h = (Math.imul(31, h) + s.charCodeAt(i)) | 0;

  return h.toString();
}

import {
  NestedCommand,
  NestedExclusionGroup,
  NestedParameter,
  NestedTool,
} from "../types/commandly-nested";
import type { Tool, Command, Parameter } from "@/registry/commandly/lib/types/commandly";

export const convertToNestedStructure = (tool: Tool): NestedTool => {
  const globalParameters = tool.parameters.filter((p) => p.isGlobal);

  const convertParameter = (param: Parameter): NestedParameter => {
    const { ...rest } = param;
    return {
      ...rest,
      validations: param.validations?.map((v) => {
        return {
          validationType: v.validationType,
          validationValue: v.validationValue,
          errorMessage: v.errorMessage,
        };
      }),
      metadata: param.metadata,
      dataType: param.dataType,
      dependencies: param.dependencies?.map((dep) => {
        const dependsOnParam = tool.parameters.find((p) => p.key === dep.dependsOnParameterKey);
        return {
          dependsOnParameter: dependsOnParam?.longFlag || "",
          dependencyType: dep.dependencyType,
          conditionValue: dep.conditionValue,
        };
      }),
    };
  };

  const buildNestedCommands = (commands: Command[], parentKey?: string): NestedCommand[] => {
    return commands
      .filter((cmd) => cmd.parentCommandKey === parentKey)
      .map((cmd) => {
        const commandParameters = tool.parameters.filter(
          (p) => p.commandKey === cmd.key && !p.isGlobal,
        );
        return {
          name: cmd.name,
          description: cmd.description,
          isDefault: cmd.isDefault ?? false,
          sortOrder: cmd.sortOrder ?? 0,
          parameters: commandParameters.map(convertParameter),
          subcommands: buildNestedCommands(commands, cmd.key),
        };
      });
  };

  const nestedExclusionGroups: NestedExclusionGroup[] | undefined = tool.exclusionGroups?.map(
    (group) => {
      return {
        name: group.name,
        exclusionType: group.exclusionType,
        parameters: group.parameterKeys.map((pk) => {
          const param = tool.parameters.find((p) => p.key === pk);
          return param?.longFlag || "";
        }),
      };
    },
  );

  return {
    name: tool.name,
    url: tool.url,
    displayName: tool.displayName,
    description: tool.description,
    version: tool.version,
    metadata: tool.metadata,
    globalParameters: globalParameters.map(convertParameter),
    commands: buildNestedCommands(tool.commands),
    exclusionGroups: nestedExclusionGroups,
  };
};
